from flask import Flask, request
import psycopg2

app = Flask(__name__)

def get_query(table_name, column_names=None, filter_conditions=None):
    query = f"SELECT * FROM {table_name}"
    
    if column_names:
        query = f"SELECT {', '.join(column_names)} FROM {table_name}"
        
    if filter_conditions:
        query += " WHERE " + ' AND '.join([f"{k}='{v}'" for k, v in filter_conditions.items()])
    
    return query

@app.route('/api/database', methods=['POST'])
def database():
    data = request.get_json(force=True)
    
    table_name = data.get('table') 
    column_names = data.get('columns')  
    filter_conditions = data.get('filter') 

    conn = psycopg2.connect(
        database="your_database",
        user="username",
        password="password",
        host="hostname",
        port="portnum")
    
    cur = conn.cursor()
    
    query = get_query(table_name, column_names, filter_conditions) 
    cur.execute(query)
        
    columns = [desc[0] for desc in cur.description]
    results = []

    for row in cur.fetchall():
        result = dict(zip(columns, row))
        results.append(result)
    
    conn.close() 

    return {'data': results} 

if __name__ == '__main__':
    app.run(debug=True)